from pathlib import Path
from collections import defaultdict
from datetime import date, datetime
from typing import Dict, Any
import json

MEMORY_FILE = Path("echo_memory.json")

class TaskManager:
    def __init__(self):
        self.tasks = defaultdict(lambda: defaultdict(list))

    def load_memory(self) -> Dict[str, Any]:
        if not MEMORY_FILE.exists():
            return {}
        with MEMORY_FILE.open("r") as f:
            return json.loads(f.read())

    def parse_tasks(self, memory: Dict[str, Any]) -> Dict[str, Dict[date, list]]:
        tasks = defaultdict(lambda: defaultdict(list))
        for wf_id, data in memory.items():
            if not isinstance(data, dict) or "tasks" not in data:
                continue
            for date_str, task_data in data["tasks"].items():
                try:
                    due_date = datetime.strptime(date_str, "%Y-%m-%dT%H:%MZ").date()
                    tasks[wf_id][due_date].append(task_data)
                except ValueError:
                    pass  # Log?
        return dict(tasks)  # Snapshot

    def add_task(self, workflow_id: str, task_data: Dict[str, Any]):
        if workflow_id not in self.tasks:
            self.tasks[workflow_id] = defaultdict(list)
        today_date = date.today()
        self.tasks[wf_id][today_date].append(task_data)

        # Simulate chat integration
        print(f"Task added for today ({today_date}): {task_data}")

    def add_task_today(self, workflow_id: str, task_data: Dict[str, Any]):
        return self.add_task(workflow_id, task_data)

# Example usage
if __name__ == "__main__":
    tm = TaskManager()

    # Load existing tasks from memory file
    memory = tm.load_memory()
