    for wf_id, data in parsed_tasks.items():
        print(f"Workflow ID: {wf_id}")
        for due_date, task_list in data.items():
            print(f"  Due Date: {due_date}")
            for task in task_list:
                print(f"    - Task: {task}")

    # Add a new task for today
    tm.add_task_today("personal", {"description": "Fix chat integration", "priority": "high"})
```

